// Quantity.tsx
import React, { useState } from "react";
import { useDispatch } from "react-redux";
import { updateQuantity } from '../../../app'
import styles from "./quantity.module.css";

interface QuantityProps {
  itemId: number;
  quantity: number;
}

const Quantity: React.FC<QuantityProps> = ({ itemId, quantity }) => {
  const dispatch = useDispatch();
  const [localQuantity, setLocalQuantity] = useState(quantity);

  const handleIncrement = () => {
    const newQuantity = localQuantity + 1;
    setLocalQuantity(newQuantity);
    dispatch(updateQuantity({ id: itemId, quantity: newQuantity }));
  };

  const handleDecrement = () => {
    if (localQuantity > 1) {
      const newQuantity = localQuantity - 1;
      setLocalQuantity(newQuantity);
      dispatch(updateQuantity({ id: itemId, quantity: newQuantity }));
    }
  };

  return (
    <div className={styles.wrapper_buttons}>
      <button className={styles.btn_quanity} onClick={handleDecrement}> - </button>
      <span className={styles.count_quantity}>{localQuantity}</span>
      <button className={styles.btn_quanity} onClick={handleIncrement}> + </button>
    </div>
  );
};

export default Quantity;




